                let stderr = String::from_utf8_lossy(&output.stderr);
                eprintln!("[ERROR] `git commit` failed:\n{}", stderr);
            }
        }
        Err(e) => {
            eprintln!("[ERROR] Failed to execute `git commit`: {}", e);
        }
    }
